            ContentJson = """{"title":"Scheduling Field Reference","groups":[{"heading":"Tabs","items":[{"label":"Schedule","value":"The master list of all scheduled operations, shown as a sortable, filterable data table (one row per operation) — not a graphical Gantt chart. Hosts the Run Scheduler button and the per-operation lock toggle. Default tab when you open Scheduling."},{"label":"Dispatch","value":"A work-center-specific, priority-ordered queue of what to run next. Select a work center, click Load to populate the list."},{"label":"Work Centers","value":"Master data for production resources (machines, stations). Full create / edit / delete."},{"label":"Shifts","value":"Read-only list of operating-hours definitions (start, end, breaks, net hours). Shifts are global, shared across all work centers."},{"label":"Run History","value":"Audit log of every scheduler execution with run date, direction, status, operations scheduled, and conflicts detected."}]},{"heading":"KPI Chips (Top of Page)","items":[{"label":"Scheduled Ops","value":"Total count of operations currently on the schedule."},{"label":"In Progress","value":"Count of operations currently running (amber value)."},{"label":"Work Centers","value":"Count of work centers (primary-color value)."}]},{"heading":"Work Center Dialog Fields","items":[{"label":"Code (required)","value":"Short identifier for the work center (e.g., 'CNC-01'). Text input, max 50 characters."},{"label":"Name (required)","value":"Full descriptive name (e.g., 'Machining Center'). Text input, max 200 characters."},{"label":"Description","value":"Optional free-form description. Textarea, 2 rows."},{"label":"Daily Capacity (Hours) (required)","value":"How many hours of work the center can absorb per day. Number input. This is a primary input to the scheduler's capacity math."},{"label":"Efficiency % (required)","value":"Realism factor applied to capacity. 100% = rated capacity; lower values account for downtime/rework. Number input with '%' suffix."},{"label":"Number of Machines (required)","value":"Count of identical units in the center that can run in parallel. Number input."},{"label":"Sort Order","value":"Optional display ordering value. Number input."},{"label":"Labor Cost / Hour","value":"Optional labor rate for costing. Currency input ($)."},{"label":"Burden Rate / Hour","value":"Optional overhead rate for costing. Currency input ($)."},{"label":"Active","value":"Toggle, shown in edit mode only. Inactive work centers are excluded from scheduling."}]},{"heading":"Scheduled Operation Statuses (Schedule Tab)","items":[{"label":"Scheduled (info chip)","value":"Operation is placed on the schedule but has not started."},{"label":"InProgress (warning chip)","value":"Operation is currently being run."},{"label":"Complete (success chip)","value":"Operation finished successfully."},{"label":"Cancelled (muted chip)","value":"Operation was cancelled."}]},{"heading":"Schedule Run Statuses (Run History Tab)","items":[{"label":"Completed (success chip)","value":"The scheduler run finished successfully."},{"label":"Running (warning chip)","value":"The scheduler is currently executing."},{"label":"Failed (error chip)","value":"The scheduler run failed with an error."},{"label":"Queued","value":"The run is queued and has not started yet."}]},{"heading":"Schedule Direction","items":[{"label":"Forward","value":"Schedule from today forward, placing work as early as capacity allows (capacity-driven)."},{"label":"Backward","value":"Schedule from the due date backward (deadline-driven), to just meet delivery dates."}]},{"heading":"Schedule Tab Columns","items":[{"label":"Job #","value":"Sortable. The job the operation belongs to. Width 100px."},{"label":"Operation","value":"Sortable. The operation title."},{"label":"Work Center","value":"Sortable, filterable. The center the operation is assigned to."},{"label":"Start / End","value":"Sortable. Scheduled start and end, date type. Width 140px each."},{"label":"Hours","value":"Sortable. Total scheduled hours for the operation. Number, width 80px."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip. Width 100px."},{"label":"Locked","value":"Lock / unlock toggle icon. Locked operations are not moved by the scheduler. Width 70px."}]},{"heading":"Dispatch Tab Columns","items":[{"label":"Job #","value":"Sortable. The job for the operation. Width 100px."},{"label":"Operation","value":"Sortable. The operation title."},{"label":"Seq","value":"Sortable. Sequence number within the queue. Width 60px."},{"label":"Start","value":"Sortable. Scheduled start, date type. Width 140px."},{"label":"Setup Hrs / Run Hrs","value":"Sortable. Setup and run hours for the operation. Number, width 100px each."},{"label":"Priority","value":"Sortable. The job's priority, shown as an info chip. Width 90px."},{"label":"Due Date","value":"Sortable. The job's due date, date type. Width 120px."}]},{"heading":"Work Centers Tab Columns","items":[{"label":"Code / Name","value":"Sortable. Work center identifier and full name."},{"label":"Daily Cap","value":"Sortable. Daily capacity hours. Number, width 120px."},{"label":"Efficiency","value":"Sortable. Efficiency percent. Number, width 110px."},{"label":"Machines","value":"Sortable. Number of machines. Number, width 90px."},{"label":"Active","value":"Sortable. Active/inactive chip (success when active, muted when inactive). Width 70px."},{"label":"Asset / Location","value":"Sortable. Linked asset name and location name."},{"label":"Actions","value":"Edit and Delete icon buttons. Width 90px."}]},{"heading":"Shifts Tab Columns","items":[{"label":"Name","value":"Sortable. The shift name."},{"label":"Start Time / End Time","value":"Sortable. Shift start and end times. Width 100px each."},{"label":"Break Min","value":"Sortable. Break minutes. Number, width 100px."},{"label":"Net Hours","value":"Sortable. Computed as end − start − breaks. Number, width 100px."},{"label":"Active","value":"Sortable. Active/inactive chip. Width 70px."}]},{"heading":"Run History Tab Columns","items":[{"label":"Run Date","value":"Sortable. When the run was executed. Date, width 140px."},{"label":"Direction","value":"Sortable. Forward or Backward. Width 100px."},{"label":"Status","value":"Sortable, filterable (enum). Completed / Running / Failed chip. Width 100px."},{"label":"Ops Scheduled","value":"Sortable. How many operations the run scheduled. Number, width 120px."},{"label":"Conflicts","value":"Sortable. How many conflicts the run detected. Number, width 100px."},{"label":"Completed","value":"Sortable. When the run completed. Date, width 140px."}]},{"heading":"Buttons and Actions","items":[{"label":"Run Scheduler (Schedule tab)","value":"Executes the auto-scheduler. data-testid: scheduling-run-btn"},{"label":"Lock / Unlock (Schedule tab row)","value":"Toggles whether the scheduler may move the operation. Lock icon (locked) / lock_open icon (unlocked)."},{"label":"Work Center selector + Load (Dispatch tab)","value":"Choose a work center, then click Load to populate its dispatch queue. Load is disabled until a work center is selected."},{"label":"New Work Center (Work Centers tab)","value":"Opens the work center create dialog. data-testid: work-center-create-btn"},{"label":"Edit (Work Centers row)","value":"Pencil icon. Opens the work center dialog in edit mode for that row, pre-filled with its current values. Edit mode adds an Active toggle the create form doesn't show. Save Changes commits; Cancel discards."},{"label":"Delete (Work Centers row)","value":"Red trash icon (danger button). Does not delete instantly — opens a confirmation dialog naming the work center; confirm with Delete or back out with Cancel."},{"label":"Cancel / Save (dialog footer)","value":"Cancel closes without saving; Save (or Create) commits. Save is disabled while the form is invalid or saving; a validation button surfaces violations."}]},{"heading":"Key Concepts","items":[{"label":"Capacity","value":"The finite amount of work a work center can absorb, derived from daily capacity hours, efficiency, machine count, and available shift hours."},{"label":"Conflict","value":"A scheduling problem the run detects — most commonly a work center scheduled beyond its capacity."},{"label":"Lock","value":"A 'do not reschedule' marker on an operation; the scheduler plans around it."},{"label":"Net Hours","value":"A shift's productive hours = end − start − break minutes."},{"label":"Dispatch List","value":"The priority-ordered, work-center-specific queue of operations to run next — the floor-operator view."}]}]}"""
        });

